 211→const parseImageDimension = (value) => {
 212→    const parsed = Number(value);
 213→    if (!Number.isFinite(parsed)) return undefined;
 214→    return parsed;
 215→};
 216→
 217→const imageFromNodeLike = (nodeLike) => {
 218→    if (!nodeLike || typeof nodeLike !== 'object') return null;
 219→
 220→    const src = pickFirstNonEmptyString(
 221→        nodeLike.src,
 222→        nodeLike.url,
 223→        nodeLike.image_url,
 224→        nodeLike.imageUrl,
 225→        nodeLike?.payload?.src,
 226→        nodeLike?.data?.src
 227→    );
 228→    if (!src) return null;
 229→
 230→    return {
 231→        src,
 232→        width: parseImageDimension(nodeLike.width),
 233→        height: parseImageDimension(nodeLike.height),
 234→    };
 235→};
