 277→const buildShareMetaFromJournal = (journal) => {
 278→    const lexicalData = extractFromLexical(journal?.content);
 279→    const normalizedTitle = typeof journal?.title === 'string' ? normalizeWhitespace(journal.title) : '';
 280→    const title = normalizedTitle || 'Untitled Post';
 281→    const authorName = normalizeWhitespace(journal?.users?.name) || 'Someone';
 282→
 283→    let description = lexicalData.text || '';
 284→    if (!description) {
 285→        description = `Read "${title}" by ${authorName} on Iskryb`;
 286→    }
 287→
 288→    let imageCandidate = DEFAULT_OG_IMAGE_URL;
 289→    let imageCandidateSource = 'fallback';
 290→    if (lexicalData.image?.src) {
 291→        imageCandidate = lexicalData.image.src;
 292→        imageCandidateSource = 'lexical';
 293→    } else if (journal?.users?.image_url) {
 294→        imageCandidate = journal.users.image_url;
 295→        imageCandidateSource = 'author_avatar';
 296→    }
 297→
 298→    return {
 299→        title,
 300→        normalizedTitle,
 301→        description: toPreviewText(description),
 302→        imageCandidate,
 303→        imageCandidateSource
